func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx     int
		delta   float64
		score   float64
		feasible bool
	}
	for jj := range oris {
		bestCand := cand{-1, 1e100, 1e100, false}
		secondBest := cand{-1, 1e100, 1e100, false}
		thirdBest := cand{-1, 1e100, 1e100, false}
		ori, des := oris[jj], dess[jj]
		shipID := total_ship + jj
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			if prevCost < 0 {
				continue
			}
			ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					delta := newCost - prevCost
					spatialPenalty := cal_dis(ori, des) * 0.01
					temporalFeasibilityScore := 0.0
					if ori.TimeStart > 0 && des.TimeEnd > 0 {
						timeWindowWidth := float64(des.TimeEnd - ori.TimeStart)
						if timeWindowWidth > 0 {
							temporalFeasibilityScore = 50.0 / timeWindowWidth
						}
					}
					scoreVal := delta*0.6 + spatialPenalty*0.25 + temporalFeasibilityScore*0.15
					c := cand{ii, delta, scoreVal, true}
					if scoreVal < bestCand.score {
						thirdBest = secondBest
						secondBest = bestCand
						bestCand = c
					} else if scoreVal < secondBest.score {
						thirdBest = secondBest
						secondBest = c
					} else if scoreVal < thirdBest.score {
						thirdBest = c
					}
				}
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		selectedIdx := -1
		if bestCand.feasible {
			if dispatch.AssignsLen == 0 {
				selectedIdx = bestCand.idx
			} else {
				regretValue := 0.0
				if secondBest.feasible && thirdBest.feasible {
					regretValue = (secondBest.score - bestCand.score) + 0.5*(thirdBest.score - secondBest.score)
				} else if secondBest.feasible {
					regretValue = secondBest.score - bestCand.score
				} else {
					regretValue = 0.0
				}
				thresholdFactor := 1.8
				if regretValue > thresholdFactor*bestCand.delta {
					explorationIdx := -1
					minComboScore := 1e100
					for ii := 0; ii < dispatch.AssignsLen; ii++ {
						prevCost := dispatch.Assigns[ii].Cost
						if prevCost < 0 {
							continue
						}
						ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
						if ok {
							dispatch.Assigns[ii].GenRoute()
							newCost := dispatch.Assigns[ii].Cost
							if newCost >= 0 {
								delta := newCost - prevCost
								spatialPenalty := cal_dis(ori, des) * 0.008
								temporalFeasibilityScore := 0.0
								if ori.TimeStart > 0 && des.TimeEnd > 0 {
									timeWindowWidth := float64(des.TimeEnd - ori.TimeStart)
									if timeWindowWidth > 0 {
										temporalFeasibilityScore = 60.0 / timeWindowWidth
									}
								}
								comboScore := delta*0.65 + spatialPenalty*0.20 + temporalFeasibilityScore*0.15 + 10.0/float64(ii+1)
								if comboScore < minComboScore {
									minComboScore = comboScore
									explorationIdx = ii
								}
							}
							dispatch.Assigns[ii].RemoveShip(shipID)
							dispatch.Assigns[ii].GenRoute()
						}
					}
					if explorationIdx >= 0 && minComboScore < bestCand.score*1.12 {
						selectedIdx = explorationIdx
					} else {
						selectedIdx = bestCand.idx
					}
				} else {
					selectedIdx = bestCand.idx
				}
			}
		}
		if selectedIdx < 0 {
			seedIdx := dispatch.AssignsLen
			if seedIdx < MAXASSIGNS {
				ok := dispatch.Assigns[seedIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[seedIdx].GenRoute()
					if dispatch.Assigns[seedIdx].Cost >= 0 {
						dispatch.AssignsLen++
						selectedIdx = seedIdx
					} else {
						dispatch.Assigns[seedIdx].RemoveShip(shipID)
						dispatch.Assigns[seedIdx].GenRoute()
					}
				}
			}
		}
		if selectedIdx >= 0 {
			dispatch.Assigns[selectedIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[selectedIdx].GenRoute()
		} else {
			for ii := 0; ii < MAXASSIGNS; ii++ {
				ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						if ii >= dispatch.AssignsLen {
							dispatch.AssignsLen = ii + 1
						}
						break
					} else {
						dispatch.Assigns[ii].RemoveShip(shipID)
						dispatch.Assigns[ii].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

